  const [activeTab, setActiveTab] = useState("8-9");
  const [visibleCards, setVisibleCards] = useState<boolean[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState<{ planName: string; amount: number } | null>(null);
  const [userDetails, setUserDetails] = useState({
    name: "",
    email: "",
    phone: "",
  });
  const { toast } = useToast();

  useEffect(() => {
    setVisibleCards([]);
    const timer = setTimeout(() => {
      setVisibleCards([true, true]);
    }, 100);
    return () => clearTimeout(timer);
  }, [activeTab]);

  const activeCategory = categories.find((cat) => cat.id === activeTab) || categories[0];

  const createOrderMutation = useMutation({
    mutationFn: async ({ planName, amount, name, email, phone }: { planName: string; amount: number; name: string; email: string; phone: string }) => {
      const res = await apiRequest("POST", "/api/create-order", { planName, amount, name, email, phone });
      return await res.json();
    },
    onSuccess: (data: any, variables) => {
      if (typeof window.Razorpay !== "undefined") {
        const options = {
          key: data.key,
          amount: variables.amount * 100,
          currency: "INR",
          name: "Career Compass",
          description: variables.planName,
          order_id: data.orderId,
          handler: async function (response: any) {
            try {
              await apiRequest("POST", "/api/verify-payment", {
                razorpayPaymentId: response.razorpay_payment_id,
                razorpayOrderId: response.razorpay_order_id,
                razorpaySignature: response.razorpay_signature,
                paymentId: data.paymentId,
              });
              toast({
                title: "Payment Successful!",
                description: "We'll contact you shortly to begin your career guidance journey.",
              });
            } catch (error) {
              toast({
                title: "Payment Verification Failed",
                description: "Please contact us with your payment details.",
                variant: "destructive",
              });
            }
          },
          prefill: {
            name: variables.name,
            email: variables.email,
            contact: variables.phone,
          },
          theme: {
            color: "#D4AF37",
          },
        };

        const rzp = new window.Razorpay(options);
        rzp.open();
      } else {
        toast({
          title: "Payment Gateway Loading",
          description: "Please wait a moment and try again.",
          variant: "destructive",
        });
      }
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to initiate payment. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handlePayment = (planName: string, amount: number) => {
    setSelectedPlan({ planName, amount });
    setIsModalOpen(true);
  };

  const handleModalSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!userDetails.name || !userDetails.email || !userDetails.phone) {
      toast({
        title: "Missing Information",
        description: "Please fill in all fields.",
        variant: "destructive",
      });
      return;
    }

    if (selectedPlan) {
      setIsModalOpen(false);
      createOrderMutation.mutate({
        planName: selectedPlan.planName,
        amount: selectedPlan.amount,
        name: userDetails.name,
        email: userDetails.email,
        phone: userDetails.phone,
      });
    }
