import { useQuery } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { Card, CardContent, CardFooter, CardHeader } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ArrowLeft, ArrowRight, Calendar, BookOpen } from "lucide-react";
import type { Blog } from "@shared/schema";

export default function AllBlogs() {
  const [, navigate] = useLocation();

  const { data, isLoading } = useQuery<{ success: boolean; blogs: Blog[] }>({
    queryKey: ["/api/blogs"],
  });

  const blogs = data?.blogs || [];

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-accent mb-4"></div>
          <p className="text-muted-foreground">Loading blog posts...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 md:px-8 py-8 sm:py-12">
        <div className="flex items-center justify-between mb-8">
          <Button
            variant="ghost"
            onClick={() => navigate("/")}
            data-testid="button-back-home"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Home
          </Button>
        </div>

        <div className="text-center mb-12">
          <div className="inline-block mb-4">
            <span className="text-accent font-semibold text-sm sm:text-base tracking-wider uppercase flex items-center gap-2 justify-center">
              <BookOpen className="w-4 h-4" />
              All Blog Posts
            </span>
          </div>
          <h1 className="font-serif font-bold text-3xl sm:text-4xl md:text-5xl text-foreground mb-4">
            Insights & Guidance
          </h1>
          <p className="text-muted-foreground max-w-2xl mx-auto">
            Explore our complete collection of career guidance articles and resources
          </p>
        </div>

        {blogs.length === 0 ? (
          <Card>
            <CardContent className="flex flex-col items-center justify-center py-16">
              <BookOpen className="w-16 h-16 text-muted-foreground mb-4" />
              <p className="text-xl font-semibold text-foreground mb-2">No blog posts yet</p>
              <p className="text-muted-foreground">Check back soon for new content</p>
            </CardContent>
          </Card>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 sm:gap-8">
            {blogs.map((blog) => (
              <Card
                key={blog.id}
                className="h-full backdrop-blur-xl bg-card border-2 border-card-border hover:border-accent/50 hover:-translate-y-3 hover:shadow-2xl hover:shadow-accent/10 transition-all duration-500 flex flex-col group overflow-hidden"
                data-testid={`card-blog-${blog.id}`}
              >
                <CardHeader className="p-0">
                  <div className={`aspect-video bg-gradient-to-br ${blog.gradient} rounded-t-lg relative overflow-hidden group-hover:scale-105 transition-transform duration-500`}>
                    <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent"></div>
                    <div className="absolute top-4 left-4">
                      <Badge className="bg-white/90 text-foreground backdrop-blur-sm hover:bg-white shadow-lg">
                        {blog.category}
                      </Badge>
                    </div>
                  </div>
                </CardHeader>

                <CardContent className="flex-grow p-4 sm:p-6">
                  <h3 className="font-serif font-bold text-lg sm:text-xl text-card-foreground mb-3 group-hover:text-accent transition-colors line-clamp-2">
                    {blog.title}
                  </h3>
                  <p className="font-sans text-sm sm:text-base text-muted-foreground leading-relaxed line-clamp-3">
                    {blog.excerpt}
                  </p>
                </CardContent>

                <CardFooter className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3 pt-4 border-t border-card-border p-4 sm:p-6">
                  <div className="flex items-center gap-4 text-xs sm:text-sm text-muted-foreground">
                    <div className="flex items-center gap-2">
                      <Calendar className="w-3 h-3 sm:w-4 sm:h-4" />
                      <span>{blog.date}</span>
                    </div>
                    <span className="text-accent">{blog.readTime}</span>
                  </div>
                  <button
                    onClick={() => navigate(`/blog/${blog.id}`)}
                    className="flex items-center gap-2 text-accent hover:gap-3 transition-all font-semibold text-sm group/btn"
                    data-testid={`button-read-${blog.id}`}
                  >
                    Read More
                    <ArrowRight className="w-4 h-4 group-hover/btn:translate-x-1 transition-transform" />
                  </button>
                </CardFooter>
              </Card>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

client/src/pages/BlogDetail.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { useRoute, useLocation } from "wouter";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ArrowLeft, Calendar, Clock } from "lucide-react";
import type { Blog } from "@shared/schema";

export default function BlogDetail() {
  const [, params] = useRoute("/blog/:id");
  const [, navigate] = useLocation();
  const blogId = params?.id;

  const { data, isLoading, isError } = useQuery<{ success: boolean; blog: Blog }>({
    queryKey: [`/api/blogs/${blogId}`],
    enabled: !!blogId,
  });

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-accent mb-4"></div>
          <p className="text-muted-foreground">Loading blog post...</p>
        </div>
      </div>
    );
  }

  if (isError || !data?.blog) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Card className="max-w-md">
          <CardContent className="pt-6 text-center">
            <p className="text-xl font-semibold text-foreground mb-4">Blog post not found</p>
            <Button onClick={() => navigate("/")}>
              <ArrowLeft className="w-4 h-4 mr-2" />
              Back to Home
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  const blog = data.blog;

  return (
    <div className="min-h-screen bg-background">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 md:px-8 py-8 sm:py-12">
        <Button
          variant="ghost"
          onClick={() => navigate("/")}
          className="mb-6"
          data-testid="button-back"
        >
          <ArrowLeft className="w-4 h-4 mr-2" />
          Back to Home
        </Button>

        <Card className="overflow-hidden">
          <CardHeader className="p-0">
            <div className={`aspect-[21/9] bg-gradient-to-br ${blog.gradient} relative`}>
              <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent"></div>
              <div className="absolute bottom-6 left-6">
                <Badge className="bg-white/90 text-foreground backdrop-blur-sm mb-3">
                  {blog.category}
                </Badge>
              </div>
            </div>
          </CardHeader>

          <CardContent className="p-6 sm:p-10">
            <h1 className="font-serif font-bold text-3xl sm:text-4xl md:text-5xl text-foreground mb-6" data-testid="text-blog-title">
              {blog.title}
            </h1>

            <div className="flex flex-wrap items-center gap-4 mb-8 text-sm text-muted-foreground">
              <div className="flex items-center gap-2">
                <Calendar className="w-4 h-4" />
                <span data-testid="text-blog-date">{blog.date}</span>
              </div>
              <div className="flex items-center gap-2">
                <Clock className="w-4 h-4" />
                <span>{blog.readTime}</span>
              </div>
            </div>

            <div className="prose prose-lg max-w-none" data-testid="text-blog-content">
              {blog.content.split('\n').map((paragraph, index) => {
                if (!paragraph.trim()) return null;

                if (paragraph.trim().startsWith('**') && paragraph.trim().endsWith('**')) {
                  const text = paragraph.trim().slice(2, -2);
                  return (
                    <h3 key={index} className="font-serif font-bold text-2xl text-foreground mt-8 mb-4">
                      {text}
                    </h3>
                  );
                }

                if (paragraph.trim().match(/^\d+\./)) {
                  return (
                    <p key={index} className="text-foreground leading-relaxed mb-4 ml-4">
                      {paragraph}
                    </p>
                  );
                }

                if (paragraph.trim().startsWith('-')) {
                  return (
                    <p key={index} className="text-foreground leading-relaxed mb-2 ml-4">
                      {paragraph}
                    </p>
                  );
                }

                return (
                  <p key={index} className="text-foreground leading-relaxed mb-6">
                    {paragraph.split('**').map((part, i) => 
                      i % 2 === 1 ? <strong key={i} className="font-semibold text-accent">{part}</strong> : part
                    )}
                  </p>
                );
              })}
            </div>

            <div className="mt-12 pt-8 border-t border-border">
              <div className="flex flex-col sm:flex-row gap-4 justify-between items-start sm:items-center">
                <div>
                  <p className="text-sm text-muted-foreground mb-1">Found this helpful?</p>
                  <p className="text-foreground">Share your career challenges with us</p>
                </div>
                <Button onClick={() => {
                  navigate("/");
                  setTimeout(() => {
                    document.getElementById("contact")?.scrollIntoView({ behavior: "smooth" });
                  }, 100);
                }} data-testid="button-contact">
                  Get in Touch
                </Button>
              </div>
            </div>
          </CardContent>
        </Card>

        <div className="mt-8 text-center">
          <Button
            variant="outline"
            onClick={() => navigate("/blogs")}
            data-testid="button-view-all"
          >
            View All Blog Posts
          </Button>
        </div>
      </div>
    </div>
  );
}
